class ListNode {
    constructor(val, next = null) {
        this.val = val;
        this.next = next;
    }
}

function criticalDistance(head) {
    let minDistance = Infinity, maxDistance = -Infinity;
    let lastCP = -1, index = 0;

    for(let current = head.next; current && current.next; current = current.next) {
        if ((current.val > current.next.val && current.val > current.prev.val) ||
            (current.val < current.next.val && current.val < current.prev.val)) {

            if (lastCP !== -1) {
                minDistance = Math.min(minDistance, index - lastCP);
                maxDistance = Math.max(maxDistance, index - lastCP);
            }
            lastCP = index;
        }
        index++;
    }

    if (minDistance !== Infinity) {
        return [minDistance, maxDistance];
    }
    return [-1, -1];
}
```

    1. Initialize minDistance, maxDistance, lastCP (last critical point), and index.
2. Loop through the list starting from the second element (since the head can't be a critical point) and check if it's a local minima or maxima.
3. If current node is a critical point and not the first one, we calculate the distance between current and last critical points, and update the min and max distances accordingly.
4. After looping through the list, if minDistance isn't infinity, we return the min and max distances; otherwise, we return [-1, -1] as there were no critical points found.

