import java.util.LinkedList;

class ListNode {
    int val;
    ListNode next;
    ListNode(int x) {
        val = x;
        next = null;
    }
}

public int[] criticalDistance(ListNode head) {
    int minDistance = Integer.MAX_VALUE, maxDistance = Integer.MIN_VALUE;
    int lastCP = -1, index = 0;

    for(ListNode current = head.next; current != null && current.next != null; current = current.next) {
        if ((current.val > current.next.val && current.val > current.prev.val) ||
            (current.val < current.next.val && current.val < current.prev.val)) {

            if (lastCP != -1) {
                minDistance = Math.min(minDistance, index - lastCP);
                maxDistance = Math.max(maxDistance, index - lastCP);
            }
            lastCP = index;
        }
        index++;
    }

    if (minDistance != Integer.MAX_VALUE) {
        return new int[]{minDistance, maxDistance};
    }
    return new int[]{-1, -1};
}
```

